int findMedian(vector<vector<int>>& matrix, int N, int M) {
    int minVal = INT_MAX, maxVal = INT_MIN;
    for (int i = 0; i < N; ++i) {
        minVal = min(minVal, matrix[i][0]);
        maxVal = max(maxVal, matrix[i][M-1]);
    }
    int desired = (N * M + 1) / 2;
    while (minVal < maxVal) {
        int mid = minVal + (maxVal - minVal) / 2;
        long long place = 0;
        for (int i = 0; i < N; ++i)
            place += upper_bound(matrix[i].begin(), matrix[i].end(), mid) - matrix[i].begin();
        if (place < desired) minVal = mid + 1;
        else maxVal = mid;
    }
    return minVal;
}

