int findMedian(int **matrix, int N, int M) {
    int minVal = INT_MAX, maxVal = INT_MIN;
    for (int i = 0; i < N; ++i) {
        if (M > 0) {
            if (matrix[i][0] < minVal) minVal = matrix[i][0];
            if (matrix[i][M - 1] > maxVal) maxVal = matrix[i][M - 1];
        }
    }

    int desired = (N * M + 1) / 2;
    while (minVal < maxVal) {
        int mid = minVal + (maxVal - minVal) / 2;
        long long place = 0;
        for (int i = 0; i < N; ++i)
            place += countSmallerOrEqual(matrix[i], M, mid);
        if (place < desired) minVal = mid + 1;
        else maxVal = mid;
    }
    return minVal;
}

