// Function to count how many numbers in a sorted row are <= mid
function countSmallerOrEqual(row, mid) {
    let low = 0, high = row.length - 1;
    while (low <= high) {
        let m = Math.floor((low + high) / 2);
        if (row[m] <= mid) {
            low = m + 1;
        } else {
            high = m - 1;
        }
    }
    return low;
}

// Function to find median of row-wise sorted matrix
function findMedian(matrix, N, M) {
    let minVal = Infinity;
    let maxVal = -Infinity;

    // Find the minimum element (first of each row)
    // and maximum element (last of each row)
    for (let i = 0; i < N; i++) {
        minVal = Math.min(minVal, matrix[i][0]);
        maxVal = Math.max(maxVal, matrix[i][M - 1]);
    }

    const desired = Math.floor((N * M + 1) / 2);

    // Binary search on the value range
    while (minVal < maxVal) {
        const mid = Math.floor(minVal + (maxVal - minVal) / 2);
        let place = 0;

        for (let i = 0; i < N; i++) {
            place += countSmallerOrEqual(matrix[i], mid);
        }

        if (place < desired) {
            minVal = mid + 1;
        } else {
            maxVal = mid;
        }
    }

    return minVal;
}
